import sys
from collections import deque

input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab_r, lab_c = 0, 0
    for i in range(n):
        row = list(input().strip())
        grid.append(row)
        for j in range(len(row)):
            if row[j] == 'L':
                lab_r, lab_c = i, j

    dirs = [(0,1),(0,-1),(1,0),(-1,0)]

    # free_degree[i][j] = number of free neighbors
    # non_forceable[i][j] = number of non-forceable free neighbors
    free_degree = [[0]*m for _ in range(n)]
    forceable = [[False]*m for _ in range(n)]

    for i in range(n):
        for j in range(m):
            if grid[i][j] == '#':
                continue
            cnt = 0
            for dr, dc in dirs:
                ni, nj = i+dr, j+dc
                if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                    cnt += 1
            free_degree[i][j] = cnt

    # non_forceable count starts as free_degree
    non_forceable = [row[:] for row in free_degree]

    queue = deque()
    # Lab is forceable
    forceable[lab_r][lab_c] = True
    queue.append((lab_r, lab_c))

    while queue:
        r, c = queue.popleft()
        for dr, dc in dirs:
            nr, nc = r+dr, c+dc
            if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] != '#' and not forceable[nr][nc]:
                non_forceable[nr][nc] -= 1
                if non_forceable[nr][nc] <= 1:
                    forceable[nr][nc] = True
                    queue.append((nr, nc))

    for i in range(n):
        for j in range(m):
            if grid[i][j] == '.' and forceable[i][j]:
                grid[i][j] = '+'
        print(''.join(grid[i]))

t = int(input())
for _ in range(t):
    solve()
